// 函数 = 黑盒机器
function add(a, b) {    // 参数：投入的原料
  return a + b;         // 返回值：产出的成品
}

const result = add(3, 5);  // 调用：投入 3 和 5
console.log(result);       // 8 — 产出 8

console.log(greet());  // ✅ "Hi" — 声明前调用也 OK
function greet() {
  return "Hi";
}
// 引擎实际执行：先把整个函数提升到顶部，再执行 console.log

console.log(greet());  // ❌ ReferenceError!
const greet = function() {
  return "Hi";
};
// const 有 TDZ（暂时性死区），声明前访问直接报错

function greet(name = "World") {
  return `Hello, ${name}!`;
}
greet();          // "Hello, World!"
greet("Alice");   // "Hello, Alice!"
greet(undefined); // "Hello, World!"  ← undefined 触发默认值
greet(null);      // "Hello, null!"   ← null 不触发！

function sum(...nums) {
  return nums.reduce((a, b) => a + b, 0);
}
sum(1, 2, 3);       // 6
sum(1, 2, 3, 4, 5); // 15

// 常见模式：第一个参数固定，其余收集
function log(tag, ...messages) {
  messages.forEach(msg => console.log(`[${tag}] ${msg}`));
}
log("DEBUG", "连接成功", "端口 3000");

function setup({ host, port = 3000 }) {
  console.log(`${host}:${port}`);
}
setup({ host: "localhost" });       // localhost:3000
setup({ host: "localhost", port: 8080 }); // localhost:8080

function bad() {
  return           // ⚠️ JS 自动在 return 后加分号！
  { value: 42 };   // 这行永远不会执行
}
console.log(bad());  // undefined（不是 42！）

function good() {
  return { value: 42 };  // ✅ 同一行，没有 ASI 陷阱
}
console.log(good());  // { value: 42 }

sections.text:
遇到不满足条件时直接 return，让代码更"扁平"——减少嵌套层级，可读性大幅提升。

// ❌ 嵌套写法
if (cond) { ...很多代码... }

// ✅ 提前 return
if (!cond) return;
...正常逻辑...

