// 单参数 → 省略 ()
const square = n => n * n;

// 多参数 → 用 ()
const add = (a, b) => a + b;

// 多语句 → 用 {} + return
const greet = (name) => {
  const msg = `Hello, ${name}!`;
  return msg;
};

// 返回对象字面量 → 用 () 包裹
const make = () => ({ x: 1, y: 2 });

const obj = {
  name: "Alice",
  sayHi: () => {
    console.log(this.name);  // ❌ undefined
    // 箭头函数没有自己的 this
    // this 指向定义时的外层（全局/模块）
  }
};
obj.sayHi();  // undefined

const obj = {
  name: "Alice",
  sayHi() {              // ✅ 方法简写
    console.log(this.name);  // "Alice"
  }
};
obj.sayHi();  // "Alice"

// 函数作为参数（回调函数）
const nums = [3, 1, 4, 1, 5];
nums.sort((a, b) => a - b);   // 箭头函数作为参数
console.log(nums);  // [1, 1, 3, 4, 5]

// 函数作为返回值（高阶函数）
function createMultiplier(factor) {
  return (n) => n * factor;  // 返回一个新函数
}
const double = createMultiplier(2);
const triple = createMultiplier(3);
console.log(double(5));  // 10
console.log(triple(5));  // 15

function createCounter() {
  let count = 0;               // ← 外层变量
  return () => {
    count++;                    // ← 仍能访问 count！
    return count;
  };
}

const counter = createCounter();
console.log(counter());  // 1
console.log(counter());  // 2
console.log(counter());  // 3
// count 在 createCounter 执行完后仍"活着"
